{"__typename": "Tweet", "card": {"legacy": {"binding_values": [{"key": "unified_card", "value": {"string_value": "{"component_objects":{"details_1":{"type":"grok_share","data":{"profile_user":{"id_str":"44196397","profile_image_url_https":"https:\/\/pbs.twimg.com\/profile_images\/2035314704307081216\/71U1ftM3.jpg","name":"Elon Musk","screen_name":"elonmusk","highlighted_label":{"description":"X","badge":{"url":"https:\/\/pbs.twimg.com\/profile_images\/1955359038532653056\/OSHY3ewP_bigger.jpg"},"url":{"urlType":"DeepLink","url":"https:\/\/twitter.com\/X"},"userLabelType":"BusinessLabel","userLabelDisplayType":"Badge"},"verified":false,"is_blue_verified":true},"grok_user":{"id_str":"1720665183188922368","profile_image_url_https":"https:\/\/pbs.twimg.com\/profile_images\/1893219113717342208\/Vgg2hEPa.jpg","name":"Grok","screen_name":"grok","highlighted_label":{"description":"xAI","badge":{"url":"https:\/\/pbs.twimg.com\/profile_images\/1769430779845611520\/lIgjSJGU_bigger.jpg"},"url":{"urlType":"DeepLink","url":"https:\/\/twitter.com\/xai"},"userLabelType":"BusinessLabel","userLabelDisplayType":"Badge"},"verified":false,"is_blue_verified":true,"verified_type":"Business"},"id":"1sd4cj9KnixDYJX4ZX2YmZQD1","conversation_preview":[{"message":"Tell me about the guy who figured out that severe stomach ulcers are bacterial in origin","sender":"USER","grokMode":"NORMAL","mediaUrls":[]},{"message":"Barry Marshall, an Australian physician, discovered that Helicobacter pylori bacteria cause most peptic ulcers, challenging the prevailing belief that stress or diet were the primary culprits. In the early 1980s, Marshall, alongside pathologist Robin Warren, observed H. pylori in the stomachs of ulcer patients and noted its association with inflammation. Their findings were initially met with skepticism, as the medical community dismissed the idea that bacteria could survive in the acidic stomach environment.\nTo prove their hypothesis, Marshall famously conducted a self-experiment in 1985, swallowing a culture of H. pylori. He developed gastritis, confirmed the bacteria\u2019s presence in his stomach, and successfully treated it with antibiotics, demonstrating the causal link. This work revolutionized ulcer treatment, shifting it from acid-suppressing drugs to antibiotic regimens that cure the infection.\nMarshall and Warren\u2019s persistence earned them the 2005 Nobel Prize in Physiology or Medicine for their discovery of H. pylori and its role in gastritis and peptic ulcer disease. Their findings also opened research into bacterial roles in other chronic conditions. Marshall, born in 1951, trained in medicine at the University of Western Australia and continues to contribute to microbiology and public health.","sender":"AGENT","grokMode":"NORMAL","mediaUrls":[],"deepsearchHeaders":[]}],"destination":"destination_1","allowed_actions":["ASK_IT_YOURSELF"],"metadata":{"text":"Answer by Grok"}}}},"destination_objects":{"destination_1":{"type":"browser","data":{"url_data":{"url":"https:\/\/x.com\/i\/grok\/share\/1sd4cj9KnixDYJX4ZX2YmZQD1","vanity":"Grok"}}}},"components":["details_1"]}", "type": "STRING"}}, {"key": "card_url", "value": {"scribe_key": "card_url", "string_value": "https://t.co/PFWkkmQfI0", "type": "STRING"}}], "card_platform": {"platform": {"audience": {"name": "production"}, "device": {"name": "Swift", "version": "12"}}}, "name": "unified_card", "url": "https://t.co/PFWkkmQfI0", "user_refs_results": []}, "rest_id": "https://t.co/PFWkkmQfI0"}, "core": {"user_results": {"result": {"__typename": "User", "affiliates_highlighted_label": {"label": {"badge": {"url": "https://pbs.twimg.com/profile_images/1955359038532653056/OSHY3ewP_bigger.jpg"}, "description": "X", "url": {"url": "https://twitter.com/X", "urlType": "DeepLink"}, "userLabelDisplayType": "Badge", "userLabelType": "BusinessLabel"}}, "avatar": {"image_url": "https://pbs.twimg.com/profile_images/2035314704307081216/71U1ftM3_normal.jpg"}, "core": {"created_at": "Tue Jun 02 20:12:29 +0000 2009", "name": "Elon Musk", "screen_name": "elonmusk"}, "dm_permissions": {"can_dm": false}, "follow_request_sent": false, "has_graduated_access": true, "id": "VXNlcjo0NDE5NjM5Nw==", "is_blue_verified": true, "legacy": {"default_profile": false, "default_profile_image": false, "description": "https://t.co/dDtDyVssfm", "entities": {"description": {"urls": [{"display_url": "Terafab.ai", "expanded_url": "http://Terafab.ai", "indices": [0, 23], "url": "https://t.co/dDtDyVssfm"}]}}, "fast_followers_count": 0, "favourites_count": 225171, "follow_request_sent": false, "followers_count": 239739955, "friends_count": 1319, "has_custom_timelines": true, "is_translator": false, "listed_count": 168666, "media_count": 4467, "needs_phone_verification": false, "normal_followers_count": 239739955, "notifications": false, "possibly_sensitive": false, "profile_banner_url": "https://pbs.twimg.com/profile_banners/44196397/1774145451", "profile_interstitial_type": "", "statuses_count": 101995, "time_zone": "", "translator_type": "none", "url": "", "utc_offset": 0, "want_retweets": false, "withheld_description": "", "withheld_scope": ""}, "location": {"location": ""}, "media_permissions": {"can_media_tag": false}, "parody_commentary_fan_label": "None", "privacy": {"protected": false}, "professional": {"category": [], "professional_type": "Creator", "rest_id": "1679729435447275522"}, "profile_bio": {"description": "https://t.co/dDtDyVssfm"}, "profile_image_shape": "Circle", "relationship_perspectives": {"blocked_by": false, "blocking": false, "followed_by": false, "following": false, "muting": false}, "rest_id": "44196397", "super_follow_eligible": true, "super_followed_by": false, "super_following": false, "verification": {"verified": false}}}}, "edit_control": {"edit_tweet_ids": ["1934465518532239467"], "editable_until_msecs": "1750051094000", "edits_remaining": "5", "is_edit_eligible": false}, "grok_analysis_button": false, "grok_share_attachment": {"items": [{"media_urls": [], "message": "Tell me about the guy who figured out that severe stomach ulcers are bacterial in origin"}, {"deepsearch_headers": [], "media_urls": [], "message": "Barry Marshall, an Australian physician, discovered that *Helicobacter pylori* bacteria cause most peptic ulcers, challenging the prevailing belief that stress or diet were the primary culprits. In the early 1980s, Marshall, alongside pathologist Robin Warren, observed *H. pylori* in the stomachs of ulcer patients and noted its association with inflammation. Their findings were initially met with skepticism, as the medical community dismissed the idea that bacteria could survive in the acidic stomach environment.

To prove their hypothesis, Marshall famously conducted a self-experiment in 1985, swallowing a culture of *H. pylori*. He developed gastritis, confirmed the bacteria’s presence in his stomach, and successfully treated it with antibiotics, demonstrating the causal link. This work revolutionized ulcer treatment, shifting it from acid-suppressing drugs to antibiotic regimens that cure the infection.

Marshall and Warren’s persistence earned them the 2005 Nobel Prize in Physiology or Medicine for their discovery of *H. pylori* and its role in gastritis and peptic ulcer disease. Their findings also opened research into bacterial roles in other chronic conditions. Marshall, born in 1951, trained in medicine at the University of Western Australia and continues to contribute to microbiology and public health."}]}, "is_translatable": false, "legacy": {"bookmark_count": 71, "bookmarked": false, "conversation_id_str": "1934199060249907581", "created_at": "Mon Jun 16 04:18:14 +0000 2025", "display_text_range": [27, 75], "entities": {"hashtags": [], "symbols": [], "timestamps": [], "urls": [{"display_url": "x.com/i/grok/share/1…", "expanded_url": "https://x.com/i/grok/share/1sd4cj9KnixDYJX4ZX2YmZQD1", "indices": [52, 75], "url": "https://t.co/PFWkkmQfI0"}], "user_mentions": [{"id_str": "125499355", "indices": [0, 16], "name": "Steve Jurvetson", "screen_name": "FutureJurvetson"}, {"id_str": "1249892717649219587", "indices": [17, 26], "name": "Centivax", "screen_name": "centivax"}]}, "favorite_count": 654, "favorited": false, "full_text": "@FutureJurvetson @centivax Reminds me of this story https://t.co/PFWkkmQfI0", "id_str": "1934465518532239467", "in_reply_to_screen_name": "FutureJurvetson", "in_reply_to_status_id_str": "1934199060249907581", "in_reply_to_user_id_str": "125499355", "is_quote_status": false, "lang": "en", "possibly_sensitive": false, "possibly_sensitive_editable": true, "quote_count": 10, "reply_count": 67, "retweet_count": 44, "retweeted": false, "user_id_str": "44196397"}, "rest_id": "1934465518532239467", "source": "<a href="http://twitter.com/download/iphone" rel="nofollow">Twitter for iPhone</a>", "unmention_data": {}, "views": {"count": "32684", "state": "EnabledWithCount"}}

